@import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&family=Outfit:wght@500;600;700;800&display=swap');
@import "tailwindcss";

:root {
  --bg-1: #ffffff;
  --bg-2: #f8fafc;
  --surface-1: rgba(255, 255, 255, 0.96);
  --surface-2: rgba(255, 255, 255, 0.98);
  --surface-border: rgba(203, 213, 225, 0.9);
  --text-strong: #1f2937;
  --text-soft: #526074;
  --muted: #8b98ab;
  --accent: #d8ebe2;
  --accent-2: #6f9b86;
  --ok: #6f9b86;
  --warn: #64748b;
  --alert: #1f2937;
  --ring: rgba(111, 155, 134, 0.42);
  --panel-bg: rgba(255, 255, 255, 0.98);
  --panel-border: rgba(203, 213, 225, 0.9);
  --control-bg: #ffffff;
  --control-border: #cbd5e1;
  --control-text: #334155;
  --surface-muted: #fbfdff;
  --surface-strong: #ffffff;
  --weather-hero-bg: linear-gradient(135deg, rgba(252, 247, 237, 0.96) 0%, rgba(241, 234, 217, 0.95) 100%);
  --weather-hero-shadow: 0 14px 30px rgba(15, 23, 42, 0.08);
  --weather-hero-orb-a: rgba(128, 192, 240, 0.06);
  --weather-hero-orb-b: rgba(100, 116, 139, 0.05);
  --weather-metric-bg: rgba(148, 163, 184, 0.1);
  --weather-metric-line: rgba(100, 116, 139, 0.12);
}

:root[data-theme='dark'] {
  --bg-1: #070d0a;
  --bg-2: #0a1510;
  --text-strong: #e8f3ec;
  --text-soft: #b8cdc0;
  --muted: #86a698;
  --panel-bg: rgba(8, 19, 13, 0.86);
  --panel-border: rgba(64, 111, 90, 0.58);
  --control-bg: #11241a;
  --control-border: #345b49;
  --control-text: #e8f3ec;
  --surface-muted: #0d1d15;
  --surface-strong: rgba(12, 28, 20, 0.82);
  --accent: #8fd8b1;
  --accent-2: #66b38f;
  --ok: #8fd8b1;
  --warn: #9fbcae;
  --ring: rgba(143, 216, 177, 0.5);
  --weather-hero-bg: linear-gradient(135deg, rgba(14, 30, 22, 0.94) 0%, rgba(11, 24, 18, 0.92) 100%);
  --weather-hero-shadow: 0 18px 36px rgba(0, 0, 0, 0.34), inset 0 1px 0 rgba(143, 216, 177, 0.07);
  --weather-hero-orb-a: rgba(86, 149, 119, 0.18);
  --weather-hero-orb-b: rgba(46, 74, 60, 0.2);
  --weather-metric-bg: rgba(22, 46, 34, 0.78);
  --weather-metric-line: rgba(101, 165, 133, 0.24);
}

* { box-sizing: border-box; }

body {
  background:
    radial-gradient(circle at 12% 12%, rgba(148, 163, 184, 0.08), transparent 34%),
    radial-gradient(circle at 88% 16%, rgba(143, 189, 168, 0.07), transparent 28%),
    linear-gradient(160deg, #ffffff 0%, #f8fafc 100%);
  color: var(--text-strong);
  font-family: 'Manrope', sans-serif;
  font-size: 15px;
  line-height: 1.5;
  letter-spacing: 0.005em;
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
  margin: 0;
  overflow-x: hidden;
}

:root[data-theme='dark'] body {
  background:
    radial-gradient(circle at 50% -14%, rgba(147, 240, 191, 0.2), transparent 48%),
    radial-gradient(circle at 85% 12%, rgba(86, 149, 119, 0.22), transparent 28%),
    radial-gradient(circle at 15% 16%, rgba(46, 74, 60, 0.24), transparent 32%),
    linear-gradient(165deg, #070d0a 0%, #0a1510 62%, #0b1a13 100%);
}

#root {
  min-height: 100vh;
}

h1, h2, h3, h4, .font-display {
  font-family: 'Outfit', sans-serif;
  letter-spacing: -0.02em;
  color: var(--text-strong);
}

::-webkit-scrollbar { width: 4px; }
::-webkit-scrollbar-track { background: #f1f5f9; }
::-webkit-scrollbar-thumb { background: rgba(111, 155, 134, 0.35); border-radius: 2px; }

@keyframes pulse-dot {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.5; transform: scale(1.3); }
}
@keyframes slide-in {
  from { opacity: 0; transform: translateY(16px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes fade-in {
  from { opacity: 0; }
  to { opacity: 1; }
}
@keyframes float {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}

.animate-slide-in { animation: slide-in 0.5s ease forwards; }
.animate-fade-in { animation: fade-in 0.6s ease forwards; }
.animate-float { animation: float 3s ease-in-out infinite; }

.card {
  background: #ffffff;
  border: none;
  border-radius: 14px;
  box-shadow: 0 8px 22px rgba(15, 23, 42, 0.06);
  transition: box-shadow 0.2s ease, transform 0.2s ease;
}
.card:hover {
  box-shadow: 0 16px 34px rgba(15, 23, 42, 0.1);
  transform: translateY(-1px);
}

.status-dot {
  width: 6px; height: 6px;
  border-radius: 50%;
  display: inline-block;
}
.status-ok { background: #6f9b86; }
.status-warn { background: #64748b; }
.status-alert { background: #1f2937; }

.nav-item {
  display: flex; align-items: center; gap: 8px;
  padding: 9px 12px; border-radius: 10px;
  font-size: 13px; font-weight: 500;
  color: var(--text-soft); cursor: pointer;
  transition: background-color 0.2s ease, color 0.2s ease, transform 0.2s ease;
}
.nav-item:hover {
  background: #f6faf8;
  color: #1e293b;
  transform: translateX(2px);
}
.nav-item.active {
  background: #f2f8f4;
  color: #3f6f5b;
  font-weight: 600;
}

.top-nav-shell {
  position: relative;
  display: flex;
  align-items: center;
  gap: 6px;
  background: rgba(232, 243, 236, 0.94);
  padding: 4px;
  border-radius: 999px;
  box-shadow: inset 0 1px rgba(111, 155, 134, 0.22);
  overflow-x: auto;
  max-width: 100%;
}

.top-nav-indicator {
  position: absolute;
  top: 4px;
  bottom: 4px;
  left: 0;
  border-radius: 999px;
  background: #101827;
  box-shadow: 0 8px 18px rgba(15, 23, 42, 0.22);
  transition: transform 0.62s cubic-bezier(0.22, 1, 0.36, 1), width 0.62s cubic-bezier(0.22, 1, 0.36, 1), opacity 0.28s ease;
  z-index: 0;
  pointer-events: none;
}

.top-nav-pill {
  border: none;
  background: transparent;
  color: var(--text-soft);
  border-radius: 999px;
  padding: 7px 12px;
  font-size: 12px;
  font-weight: 700;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  cursor: pointer;
  white-space: nowrap;
  position: relative;
  z-index: 1;
  transition: color 0.25s ease;
}

.top-nav-pill.active {
  color: #ecf4ef;
}

.top-icon-btn {
  width: 32px;
  height: 32px;
  border: none;
  border-radius: 999px;
  background: #edf6f1;
  color: var(--text-strong);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: inset 0 1px rgba(111, 155, 134, 0.22);
}

.top-avatar-chip {
  border: none;
  border-radius: 999px;
  padding: 4px 8px 4px 4px;
  background: #edf6f1;
  color: var(--text-strong);
  display: inline-flex;
  align-items: center;
  gap: 6px;
  cursor: pointer;
  box-shadow: inset 0 1px rgba(111, 155, 134, 0.22);
}

.avatar-dot {
  width: 22px;
  height: 22px;
  border-radius: 999px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 800;
  background: #ecf1bb;
  color: #1b2634;
}

@media (max-width: 1240px) {
  .top-nav-shell {
    gap: 4px;
    padding: 3px;
  }

  .top-nav-pill {
    padding: 6px 9px;
    font-size: 11px;
    gap: 5px;
  }

  .top-avatar-chip {
    padding: 3px 7px 3px 3px;
  }
}

@media (max-width: 1080px) {
  .top-nav-pill {
    padding: 6px 8px;
    font-size: 10px;
  }
}

.shell-topbar {
  backdrop-filter: none;
  background: transparent;
  border-bottom: none;
  box-shadow: none;
}

.mini-pill {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  border: none;
  background: var(--surface-muted);
  color: var(--text-soft);
  border-radius: 999px;
  padding: 6px 10px;
  font-size: 11px;
  font-weight: 600;
}

.ghost-btn {
  border: none;
  background: var(--control-bg);
  color: var(--control-text);
  border-radius: 10px;
  font-size: 12px;
  font-weight: 700;
  box-shadow: 0 5px 12px rgba(15, 23, 42, 0.08);
}

.ghost-btn:hover {
  background: var(--surface-muted);
}

.top-shortcut {
  border: none;
  background: var(--surface-muted);
  color: var(--text-strong);
  border-radius: 999px;
  padding: 6px 12px;
  font-size: 11px;
  font-weight: 700;
  cursor: pointer;
  box-shadow: inset 0 1px rgba(148, 163, 184, 0.25);
  transition: background-color 0.2s ease, transform 0.2s ease;
}

.top-shortcut:hover {
  background: #f2f8f4;
  transform: translateY(-1px);
}

.dashboard-frame {
  position: relative;
}

.dashboard-hero {
  background: linear-gradient(160deg, rgba(255, 255, 255, 0.88), rgba(248, 250, 252, 0.82));
  border: none;
  border-radius: 18px;
  padding: 14px 16px;
  box-shadow: 0 16px 34px rgba(15, 23, 42, 0.07);
}

.section-kicker {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-weight: 800;
  color: var(--muted);
}

.kpi-card {
  background: linear-gradient(180deg, rgba(255, 255, 255, 0.94), rgba(248, 250, 252, 0.92));
}

.glass-panel {
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(6px);
}

:root[data-theme='dark'] .card {
  background: rgba(11, 26, 19, 0.78);
  box-shadow: 0 16px 34px rgba(0, 0, 0, 0.32), inset 0 1px 0 rgba(143, 216, 177, 0.05);
}

:root[data-theme='dark'] .dashboard-hero {
  background: linear-gradient(160deg, rgba(10, 23, 16, 0.78), rgba(8, 19, 14, 0.74));
  box-shadow: 0 18px 34px rgba(0, 0, 0, 0.34), inset 0 1px 0 rgba(143, 216, 177, 0.07);
}

:root[data-theme='dark'] .kpi-card {
  background: linear-gradient(180deg, rgba(13, 29, 21, 0.86), rgba(11, 26, 19, 0.78));
}

:root[data-theme='dark'] .glass-panel {
  background: rgba(10, 23, 16, 0.76);
}

:root[data-theme='dark'] .nav-item:hover {
  background: rgba(143, 216, 177, 0.12);
  color: #e7f6ee;
}

:root[data-theme='dark'] .nav-item.active {
  background: rgba(143, 216, 177, 0.2);
  color: #d9f8e9;
  box-shadow: 0 10px 22px rgba(0, 0, 0, 0.25);
}

:root[data-theme='dark'] .top-nav-shell {
  background: rgba(14, 28, 21, 0.9);
  box-shadow: inset 0 1px rgba(143, 216, 177, 0.16);
}

:root[data-theme='dark'] .top-nav-indicator {
  background: #e8f2ec;
  box-shadow: 0 8px 18px rgba(0, 0, 0, 0.35);
}

:root[data-theme='dark'] .top-nav-pill {
  color: #b9d0c1;
}

:root[data-theme='dark'] .top-nav-pill.active {
  color: #0f1f17;
}

:root[data-theme='dark'] .top-icon-btn,
:root[data-theme='dark'] .top-avatar-chip {
  background: rgba(17, 36, 26, 0.9);
  color: #e8f3ec;
  box-shadow: inset 0 1px rgba(143, 216, 177, 0.2);
}

:root[data-theme='dark'] .avatar-dot {
  background: #304e3f;
  color: #e8f3ec;
}

:root[data-theme='dark'] .shell-topbar {
  box-shadow: none;
}

:root[data-theme='dark'] .mini-pill {
  background: rgba(17, 36, 26, 0.9);
  color: #cde6d8;
  border-color: rgba(74, 128, 103, 0.52);
}

:root[data-theme='dark'] .ghost-btn:hover {
  background: rgba(143, 216, 177, 0.12);
  color: #e8f3ec;
}

:root[data-theme='dark'] .top-shortcut {
  background: rgba(17, 36, 26, 0.9);
  color: #e8f3ec;
  box-shadow: inset 0 1px rgba(143, 216, 177, 0.2);
}

:root[data-theme='dark'] .top-shortcut:hover {
  background: rgba(143, 216, 177, 0.16);
}

:root[data-theme='dark'] .chip-green {
  background: rgba(143, 216, 177, 0.16);
  color: #d8f8e8;
}

:root[data-theme='dark'] .chip-amber,
:root[data-theme='dark'] .chip-blue {
  background: rgba(33, 52, 42, 0.72);
  color: #c9dfd3;
}

:root[data-theme='dark'] ::-webkit-scrollbar-track {
  background: #0c1812;
}

:root[data-theme='dark'] ::-webkit-scrollbar-thumb {
  background: rgba(101, 165, 133, 0.45);
}

.chip {
  display: inline-flex; align-items: center; gap: 4px;
  padding: 3px 8px; border-radius: 4px;
  font-size: 11px; font-weight: 500;
}
.chip-green { background: #eef7f2; color: #3f6f5b; }
.chip-amber { background: #f8fafc; color: #475569; }
.chip-red { background: #fef2f2; color: #dc2626; }
.chip-blue { background: #f8fafc; color: #475569; }

.app-sidebar {
  border-right: none !important;
  box-shadow: 14px 0 34px rgba(15, 23, 42, 0.06);
}

:root[data-theme='dark'] .app-sidebar {
  box-shadow: 14px 0 34px rgba(0, 0, 0, 0.34);
}

button,
input,
select,
textarea {
  font-family: 'Manrope', sans-serif;
}

button:focus-visible,
input:focus-visible,
select:focus-visible,
textarea:focus-visible {
  outline: 2px solid var(--ring);
  outline-offset: 2px;
}

@media (max-width: 768px) {
  body {
    font-size: 14px;
  }

  .card {
    border-radius: 12px;
  }
}
